class Solution:
    def maxOperations(self, nums, k):
        arr = sorted(nums)
        i, j = 0, len(arr) - 1
        ops = 0
        while i < j:
            s = arr[i] + arr[j]
            if s == k:
                ops += 1
                i += 1
                j -= 1
            elif s < k:
                i += 1
            else:
                j -= 1
        return ops

