from collections import Counter
class Solution:
    def maxOperations(self, nums, k):
        cnt = Counter(nums)
        ops = 0
        for x in list(cnt.keys()):
            y = k - x
            if y not in cnt:
                continue
            if x == y:
                ops += cnt[x] // 2
            elif x < y:
                ops += min(cnt[x], cnt[y])
        return ops

