var maxOperations = function(nums, k) {
    const cnt = new Map();
    for (const x of nums) cnt.set(x, (cnt.get(x) || 0) + 1);
    let ops = 0;
    for (const x of cnt.keys()) {
        const y = k - x;
        if (!cnt.has(y)) continue;
        if (x === y) {
            ops += Math.floor(cnt.get(x) / 2);
        } else if (x < y) {
            ops += Math.min(cnt.get(x), cnt.get(y));
        }
    }
    return ops;
};
